@Override
public PageInfo<TeamRoleTreeVo> listTeamRoles(Long userId, String spaceId, Long spaceNodeId, String keyword, int pageNo, int pageSize) {
    // 1. 获取空间站小组树
    List<TeamMemberVo> teamTree = apitableGrpcClientService.getTeamMembers(spaceId, userId);

    // 2. 获取当前节点的权限数据（考虑继承）
    Map<Long, String> teamIdToRole = getTeamRoleMap(spaceId, spaceNodeId);

    // 3. 转换为 TeamRoleTreeVo
    List<TeamRoleTreeVo> tree = convertToTeamRoleTree(teamTree, teamIdToRole);

    // 4. 搜索过滤
    List<TeamRoleTreeVo> result;
    if (StrUtil.isNotBlank(keyword)) {
        result = flattenAndFilter(tree, keyword);
    } else {
        result = flattenTree(tree);
    }

    // 5. 内存分页
    int total = result.size();
    int fromIndex = Math.min((pageNo - 1) * pageSize, total);
    int toIndex = Math.min(fromIndex + pageSize, total);
    List<TeamRoleTreeVo> pageRecords = result.subList(fromIndex, toIndex);

    return PageHelper.build(pageNo, pageSize, total, pageRecords);
}

/**
 * 获取节点的小组权限映射 (teamId -> roleCode)
 */
private Map<Long, String> getTeamRoleMap(String spaceId, Long spaceNodeId) {
    String controlId;
    if (controlService.existsByControlId(spaceNodeId.toString())) {
        controlId = spaceNodeId.toString();
    } else {
        Long extendNodeId = getNodeExtendNodeId(spaceNodeId);
        controlId = extendNodeId != null ? extendNodeId.toString() : null;
    }

    if (controlId == null) {
        return Map.of();
    }

    List<ControlRoleEntity> controlRoles = controlRoleService.getByControlId(controlId);
    if (CollectionUtils.isEmpty(controlRoles)) {
        return Map.of();
    }

    List<Long> unitIds = controlRoles.stream().map(ControlRoleEntity::getUnitId).toList();
    List<NodeRoleUnit> unitInfos = apitableGrpcClientService.getNodeRoleUnitList(spaceId, unitIds);

    // unitType=1 means Department/Team
    Map<Long, Long> unitIdToRefId = unitInfos.stream()
            .filter(u -> u.getUnitType() != null && u.getUnitType() == 1)
            .collect(Collectors.toMap(NodeRoleUnit::getUnitId, NodeRoleUnit::getUnitRefId, (a, b) -> a));

    Map<Long, String> unitIdToRole = controlRoles.stream()
            .collect(Collectors.toMap(ControlRoleEntity::getUnitId, ControlRoleEntity::getRoleCode, (a, b) -> a));

    // teamId(unitRefId) -> roleCode
    Map<Long, String> teamIdToRole = new HashMap<>();
    unitIdToRefId.forEach((unitId, teamId) -> {
        String role = unitIdToRole.get(unitId);
        if (role != null) {
            teamIdToRole.put(teamId, role);
        }
    });
    return teamIdToRole;
}

private List<TeamRoleTreeVo> convertToTeamRoleTree(List<TeamMemberVo> teamTree, Map<Long, String> teamIdToRole) {
    List<TeamRoleTreeVo> result = new ArrayList<>();
    for (TeamMemberVo team : teamTree) {
        TeamRoleTreeVo vo = new TeamRoleTreeVo();
        vo.setTeamId(team.getTeamId());
        vo.setTeamName(team.getTeamName());
        vo.setParentId(team.getParentTeamId());
        vo.setMemberCount(team.getMemberCount());
        vo.setRole(teamIdToRole.get(team.getTeamId()));
        if (CollectionUtils.isNotEmpty(team.getChildrenList())) {
            vo.setChildren(convertToTeamRoleTree(team.getChildrenList(), teamIdToRole));
        } else {
            vo.setChildren(List.of());
        }
        result.add(vo);
    }
    return result;
}

/** 平铺树为列表（前序遍历） */
private List<TeamRoleTreeVo> flattenTree(List<TeamRoleTreeVo> tree) {
    List<TeamRoleTreeVo> result = new ArrayList<>();
    for (TeamRoleTreeVo node : tree) {
        result.add(node);
        if (CollectionUtils.isNotEmpty(node.getChildren())) {
            result.addAll(flattenTree(node.getChildren()));
        }
    }
    return result;
}

/** 搜索过滤：按 teamName 模糊匹配，平铺返回 */
private List<TeamRoleTreeVo> flattenAndFilter(List<TeamRoleTreeVo> tree, String keyword) {
    List<TeamRoleTreeVo> result = new ArrayList<>();
    String lowerKeyword = keyword.toLowerCase();
    for (TeamRoleTreeVo node : tree) {
        if (node.getTeamName() != null && node.getTeamName().toLowerCase().contains(lowerKeyword)) {
            result.add(node);
        }
        if (CollectionUtils.isNotEmpty(node.getChildren())) {
            result.addAll(flattenAndFilter(node.getChildren(), keyword));
        }
    }
    return result;
}
```

